INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9134088f-9250-41c1-b3b8-9f80a2024080',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS State Management — Local, Lifted, Context, and Stores Explained$escape$,
  $escape$SolidJS gives you four distinct state primitives, each with a clear use case. Use `createSignal` for local, component-scoped state — it's reactive and self-contained. When a parent needs to coordinate two siblings, lift the signal up and pass the setter as a prop; SolidJS props are reactive, so children re-render only when the value changes. For cross-tree sharing without prop-drilling, wrap a signal in `createContext` and expose it via a provider — consumers call `useContext` and receive live reactive access. For complex, structured state (nested objects, arrays, derived slices), reach for `createStore`. It gives you fine-grained, path-level reactivity via `produce`-style mutations or direct path setters, so only the exact DOM node bound to `state.items[2].name` updates. The key SolidJS distinction: stores use Proxy-based tracking, meaning reads inside JSX automatically subscribe to only the accessed paths — no selectors needed. External libraries like `@solid-primitives/signal-store` extend this further for shared global state across module boundaries.$escape$,
  $escape$import { createSignal, createContext, useContext, createStore } from 'solid-js';

// Local
const [count, setCount] = createSignal(0);

// Context
const ThemeCtx = createContext('light');
const theme = useContext(ThemeCtx);

// Store — fine-grained: only `user.name` subscribers update
const [state, setState] = createStore({ user: { name: 'Ada', age: 30 } });
setState('user', 'name', 'Grace'); // path-level update

// Derived from store — reactive slice, no selector boilerplate
const userName = () => state.user.name;$escape$,
  $escape$typescript$escape$,
