INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2d72cd61-fbb1-4229-91b9-e09dbb7cc662',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Testing — Test Behaviour, Not Signals$escape$,
  $escape$The Testing Library philosophy — query by role, test what users see — applies to SolidJS with a critical caveat: SolidJS's fine-grained reactivity runs synchronously, but DOM updates from signals still require `waitFor` or wrapping in `act` equivalents when triggered asynchronously. Use `@solidjs/testing-library` and never assert on signal values directly. Assert on the DOM.

Avoid testing that `setCount` was called or that a signal holds a specific value. Instead, fire an event and assert the rendered output changed. This decouples tests from implementation — you can refactor from `createSignal` to a `createStore` slice and your tests stay green.

`render` from `@solidjs/testing-library` mounts inside a real DOM (via jsdom/happy-dom), so `createEffect` and `createMemo` run as they would in production. Use `screen.getByRole`, fire with `userEvent`, and assert with `toHaveTextContent`. Never reach into the component closure to read signal values — if the DOM doesn't show it, the user doesn't see it.$escape$,
  $escape$import { render, screen, fireEvent } from '@solidjs/testing-library';
import userEvent from '@testing-library/user-event';
import { Counter } from './Counter';

test('increments display when button clicked', async () => {
  const user = userEvent.setup();
  render(() => <Counter />);

  const btn = screen.getByRole('button', { name: /increment/i });
  await user.click(btn);

  // Assert DOM, not signal internals
  expect(screen.getByRole('status')).toHaveTextContent('1');
});$escape$,
  $escape$typescript$escape$,
