INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a4bd6c96-9da0-4254-8a2c-924a592d455e',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Code Quality — Why eslint-plugin-react-hooks Will Lie to You$escape$,
  $escape$SolidJS's reactivity model has nothing in common with React's Rules of Hooks — yet teams migrating from React often leave eslint-plugin-react-hooks installed. This creates constant noise: the plugin flags createSignal calls inside conditionals as violations, even though SolidJS primitives have no top-level placement requirement.

Replace it with eslint-plugin-solid. Two rules matter immediately: solid/reactivity catches reactive tracking loss (e.g., reading a signal outside a tracking scope), and solid/no-destructure prevents const { x } = props — the most common SolidJS bug for React developers, since it breaks the reactive proxy entirely.

For naming conventions: signal accessors are nouns (count, not getCount) — the call syntax count() already signals invocation. Setters follow setX. Derived computations belong in createMemo, not inline JSX expressions; name memos for what they represent (filteredItems, not getFilteredItems).

Apply the 50-line rule at the component boundary. When a SolidJS component grows past 50 lines, extract either a sub-component or a create* primitive factory — createPagination(), createIntersectionObserver(). This keeps components declarative and makes primitives independently testable without a component render tree.$escape$,
  $escape$// eslint.config.js — drop react-hooks, use solid instead
import solid from "eslint-plugin-solid";
export default [
  { plugins: { solid }, rules: { "solid/reactivity": "error", "solid/no-destructure": "error" } }
];

// Extracted create* factory keeps Counter under 50 lines
function createCounter(initial = 0) {
  const [count, setCount] = createSignal(initial);
  const doubled = createMemo(() => count() * 2);
  return { count, doubled, increment: () => setCount(c => c + 1) };
}

function Counter() {
  const { count, doubled, increment } = createCounter();
  return <button onClick={increment}>{count()} (×2: {doubled()})</button>;
}$escape$,
  $escape$typescript$escape$,
