INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a10ad281-9e12-4d04-8c99-6d503a0525c5',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Accessibility — Semantic HTML First, ARIA Only When You Must$escape$,
  $escape$SolidJS's fine-grained reactivity is a hidden accessibility ally — elements update in-place rather than unmounting, so keyboard focus is rarely displaced mid-interaction. Unlike React's reconciliation, a toggled signal won't unmount your focused button. Lean on this.

Start with semantic HTML: `<button>` not `<div onClick>`, `<dialog>` not `<div role="dialog">`. Native elements carry built-in keyboard behavior and implicit ARIA roles for free. Only reach for `aria-*` when no native element fits — custom comboboxes, live regions, or composite widgets.

For programmatic focus, attach a `ref` and drive it from `createEffect`. Effects run after DOM commits, so `ref.focus()` reliably targets the correct node. Pair with `<Show>` — its `fallback` is fully removed from the DOM, so focus cannot land on hidden content.

Avoid `aria-hidden` hacks to mask misused `<div>` buttons. Fix the element first. When ARIA is genuinely needed — like `aria-live` for async notifications — wire it to a signal so screen readers receive the update precisely when the DOM changes, not on a polling delay.$escape$,
  $escape$import { createSignal, createEffect } from "solid-js";

function AccessibleDialog(props: { open: boolean; onClose: () => void; children: any }) {
  let ref!: HTMLDialogElement;

  // <dialog> gives focus-trap + role="dialog" + Escape key for free
  createEffect(() => {
    props.open ? ref.showModal() : ref.close();
  });

  return (
    <dialog ref={ref} onClose={props.onClose}>
      <button autofocus onClick={props.onClose}>Close</button>
      {props.children}
    </dialog>
  );
}

// ARIA only where HTML falls short: async live regions
const [status, setStatus] = createSignal("");
<div aria-live="polite" aria-atomic="true">{status()}</div>;$escape$,
  $escape$typescript$escape$,
