INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '29e8a7c5-425b-430f-9cc7-ab32d93e8352',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Bundle Optimization — lazy(), Tree-Shaking, and Visualizing Your Build$escape$,
  $escape$SolidJS ships a ~7kb runtime, but third-party libraries still bloat your bundle. Use `lazy()` from `solid-js` to code-split heavy components — it wraps a dynamic `import()` and integrates directly with `<Suspense>`. Unlike React, SolidJS's compiler eliminates JSX transform overhead entirely, so your tree-shaking baseline is already leaner.

For analysis, add `rollup-plugin-visualizer` to `vite.config.ts` — it outputs an interactive treemap after `vite build`. Look for duplicated polyfills or oversized charting libs that snuck in transitively.

SolidJS primitives (`createSignal`, `createMemo`, `createResource`) are individually exported from `solid-js` and fully tree-shakeable — only what you import ships. Avoid barrel re-exports from your own `utils/index.ts` files, which can defeat Rollup's static analysis. Use `sideEffects: false` in your `package.json` if you publish a component library built on Solid. For route-based splitting, `@solidjs/router` accepts lazy components natively — pair each route's `component` prop with a `lazy()` call and let the router handle the `<Suspense>` boundary.$escape$,
  $escape$// vite.config.ts
import { visualizer } from 'rollup-plugin-visualizer';
import solidPlugin from 'vite-plugin-solid';

export default defineConfig({
  plugins: [solidPlugin(), visualizer({ open: true })],
});

// routes.tsx
import { lazy } from 'solid-js';
import { Route } from '@solidjs/router';

const HeavyEditor = lazy(() => import('./features/editor/Editor'));

<Route path="/editor" component={HeavyEditor} />;$escape$,
  $escape$typescript$escape$,
