INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '17e308ab-aed6-4621-9df5-0ead383d6738',
  '00000000-0000-0000-0000-000000000001',
  $escape$SolidJS Quality Gates: Prettier, lint-staged, and tsc --noEmit That Actually Work$escape$,
  $escape$SolidJS projects commonly skip type-checking in CI because vite-plugin-solid owns compilation — tsc never runs. That's a silent gap. Wire up three gates to catch issues before they merge.

Prettier with `--parser babel-ts` handles `.tsx` files without a SolidJS-specific plugin. Drop it into lint-staged targeting `*.{ts,tsx}` alongside `eslint-plugin-solid`, which enforces signal accessor call correctness, flags missing cleanup in `onCleanup`, and prevents React-shaped patterns (e.g., calling a signal without `()` in JSX — valid in React, broken in Solid).

The critical gate is `tsc --noEmit` in CI. For it to resolve SolidJS's JSX types — `Component<P>`, `ParentComponent`, `JSX.Element`, `Accessor<T>` — your `tsconfig.json` must set `"jsx": "preserve"` and `"jsxImportSource": "solid-js"`. Without `jsxImportSource`, TypeScript falls back to React's JSX namespace and type errors become invisible. This catches mistyped store mutations, broken `createResource` return shapes, and prop mismatches that vite-plugin-solid compiles through without complaint.$escape$,
  $escape$// lint-staged.config.mjs
export default {
  "*.{ts,tsx}": [
    "prettier --write",
    "eslint --fix", // eslint-plugin-solid enforces signal/reactivity rules
  ],
};

// tsconfig.json — required for tsc --noEmit to resolve SolidJS JSX types
// "jsx": "preserve"
// "jsxImportSource": "solid-js"   ← unlocks Component, ParentProps, JSX.Element
// "strict": true

// GitHub Actions CI
// - run: npx tsc --noEmit$escape$,
  $escape$javascript$escape$,
